def head(title,desc):
    return '<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8" />\n  <meta name="viewport" content="width=device-width, initial-scale=1.0" />\n  <title>%s</title>\n  <meta name="description" content="%s" />\n  <link rel="canonical" href="https://alevoortechnologies.lovable.app" />\n  <link rel="preconnect" href="https://fonts.googleapis.com" />\n  <link href="https://fonts.googleapis.com/css2?family=Sora:wght@300;400;500;600;700;800&family=DM+Sans:wght@300;400;500;600&display=swap" rel="stylesheet" />\n  <link rel="icon" href="data:image/svg+xml,%3Csvg xmlns=\'http://www.w3.org/2000/svg\' viewBox=\'0 0 100 100\'%3E%3Ccircle cx=\'50\' cy=\'50\' r=\'50\' fill=\'%230db88a\'/%3E%3Ctext y=\'.9em\' font-size=\'50\' x=\'50%25\' text-anchor=\'middle\' fill=\'white\' font-family=\'sans-serif\' font-weight=\'bold\'%3EAT%3C/text%3E%3C/svg%3E" />\n  <link rel="stylesheet" href="/site.css" />\n</head>\n<body>\n\n<div id="loading"><img class="loading-logo" src="/assets/logo.png" alt="Alevoor Technologies" /></div>\n' % (title,desc)
